from qiskit.quantum_info import SparsePauliOp
op = SparsePauliOp.from_list([("Z", 1), ("Z", 2), ("X", 1)]).simplify()
labels = list(op.paulis.to_labels())
obs = {l: round(complex(c).real, 6) for l, c in zip(labels, op.coeffs)}
nterms = len(labels)
claims = {
    "A": ("dedup keep-largest {'Z':2,'X':1}", obs == {"Z": 2.0, "X": 1.0}),
    "B": ("sum all coeffs {'Z':3,'X':2}", obs == {"Z": 3.0, "X": 2.0}),
    "C": ("like terms summed {'Z':3,'X':1}", obs == {"Z": 3.0, "X": 1.0}),
    "D": ("unmerged (3 terms)", nterms == 3),
}
evidence = {}
proven = []
for k, (desc, ok) in claims.items():
    evidence[k] = f"simplify() -> {obs} ({nterms} terms); option {k} claims {desc} -> match={ok}"
    if ok:
        proven.append(k)
emit_verdict({"answer": proven, "evidence": evidence, "observed": {"simplified": obs, "n_terms": nterms}})
